log_queries.query:
// Detect container escape attempts
let suspiciousCapabilities = dynamic(["CAP_SYS_ADMIN", "CAP_SYS_PTRACE", "CAP_SYS_MODULE", "CAP_DAC_OVERRIDE"]);
let dangerousPaths = dynamic(["/proc/self/exe", "/proc/sys/kernel/core_pattern", "/proc/sysrq-trigger", "/sys/"]);
ContainerLog
| union AuditLogs, Syslog
| where TimeGenerated > ago(24h)
| where (
    LogEntry contains "privileged" and LogEntry contains "true"
  ) or (
    LogEntry has_any (suspiciousCapabilities)
  ) or (
    LogEntry has_any (dangerousPaths)
  ) or (
    ProcessName == "runc" and (LogEntry contains "exec" or LogEntry contains "write")
  )
| extend Severity = case(
    LogEntry contains "privileged" or LogEntry has_any (dangerousPaths), "Critical",
    LogEntry has_any (suspiciousCapabilities), "High",
    "Medium"
  )
| project TimeGenerated, Computer, ContainerName, Namespace, Image, LogEntry, Severity
| where Severity in ("Critical", "High")
| order by TimeGenerated desc

source:docker status:error OR status:warning
(@docker.container.privileged:true OR
 @process.args:(*CAP_SYS_ADMIN* OR *CAP_SYS_PTRACE*) OR
 @file.path:(/proc/self/exe OR /proc/sys/kernel/core_pattern OR /proc/sysrq-trigger) OR
 (@process.name:runc AND @event.action:(exec OR write)))
